import{_ as n,c as s,o as a,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse(`{"title":"Design Workflow: Brainstorming Requirement Clarification and Design Exploration | Superpowers Tutorial","description":"Learn how to use the brainstorming skill to clarify requirements and explore design before coding. This tutorial details Superpowers' design workflow, including understanding project context, refining requirements one question at a time, exploring 2-3 implementation approaches with trade-offs, segment-by-segment design document verification, and automatic formatted design document generation to ensure AI agents accurately understand your needs and avoid coding rework.","frontmatter":{"title":"Design Workflow: Brainstorming Requirement Clarification and Design Exploration | Superpowers Tutorial","sidebarTitle":"Design Before Coding","subtitle":"Design Workflow: Brainstorming","description":"Learn how to use the brainstorming skill to clarify requirements and explore design before coding. This tutorial details Superpowers' design workflow, including understanding project context, refining requirements one question at a time, exploring 2-3 implementation approaches with trade-offs, segment-by-segment design document verification, and automatic formatted design document generation to ensure AI agents accurately understand your needs and avoid coding rework.","tags":["Core Workflows","brainstorming","Design","Requirement Clarification"],"prerequisite":["start-using-skills"],"order":100},"headers":[],"relativePath":"obra/superpowers/core-workflows/design-workflow/index.md","filePath":"obra/superpowers/core-workflows/design-workflow/index.md"}`),i={name:"obra/superpowers/core-workflows/design-workflow/index.md"};function o(r,e,l,p,d,c){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="design-workflow-brainstorming" tabindex="-1">Design Workflow: Brainstorming <a class="header-anchor" href="#design-workflow-brainstorming" aria-label="Permalink to &quot;Design Workflow: Brainstorming&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Engage in structured design conversations with AI agents before coding</li><li>Let AI accurately understand your requirements by asking one question at a time</li><li>Evaluate trade-offs across 2-3 different implementation approaches</li><li>Review design documents segment by segment to ensure each part meets expectations</li><li>Automatically generate formatted design documents and save them to your project</li></ul><h2 id="your-current-dilemma" tabindex="-1">Your Current Dilemma <a class="header-anchor" href="#your-current-dilemma" aria-label="Permalink to &quot;Your Current Dilemma&quot;">​</a></h2><p><strong>AI agents often &quot;make assumptions&quot;</strong></p><p>Have you encountered this? You tell the AI &quot;help me add user login functionality,&quot; and it immediately starts writing code, but the end result isn&#39;t what you wanted.</p><p>Common problems:</p><ul><li>❌ AI skips requirement clarification and writes code directly</li><li>❌ No discussion of alternatives—only provides the &quot;most common&quot; implementation</li><li>❌ Discovers missing key requirements after implementation</li><li>❌ Realizes the approach is wrong halfway through coding</li></ul><p>Root cause: <strong>AI didn&#39;t fully explore and validate the design before coding.</strong></p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>The brainstorming skill automatically triggers in these scenarios:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Example</th></tr></thead><tbody><tr><td><strong>Creating new features</strong></td><td>&quot;Help me add a user comment feature&quot;</td></tr><tr><td><strong>Building components</strong></td><td>&quot;I need a reusable table component&quot;</td></tr><tr><td><strong>Adding functionality</strong></td><td>&quot;Add search filtering to existing page&quot;</td></tr><tr><td><strong>Modifying behavior</strong></td><td>&quot;Change this button&#39;s interaction logic&quot;</td></tr></tbody></table><p><strong>Core principle</strong>: Any creative work must start with brainstorming.</p><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>The brainstorming workflow is divided into four stages:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Understand Idea] --&gt; B[Explore Solutions]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Present Design]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Save Document]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style A fill:#e3f2fd</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style B fill:#fff3e0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e8f5e9</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style D fill:#f3e5f5</span></span></code></pre></div><h3 id="stage-1-understand-idea" tabindex="-1">Stage 1: Understand Idea <a class="header-anchor" href="#stage-1-understand-idea" aria-label="Permalink to &quot;Stage 1: Understand Idea&quot;">​</a></h3><p>AI first checks the current project state (files, documentation, recent commits), then <strong>asks one question at a time</strong> to refine your idea.</p><p><strong>Questioning principles</strong>:</p><ul><li>✅ One question at a time (avoid information overload)</li><li>✅ Multiple choice preferred (easier to answer)</li><li>✅ Focus on: purpose, constraints, success criteria</li></ul><h3 id="stage-2-explore-solutions" tabindex="-1">Stage 2: Explore Solutions <a class="header-anchor" href="#stage-2-explore-solutions" aria-label="Permalink to &quot;Stage 2: Explore Solutions&quot;">​</a></h3><p>AI proposes 2-3 different implementation approaches with trade-off analysis.</p><p><strong>Presentation approach</strong>:</p><ul><li>Recommend the most suitable approach first and explain why</li><li>List pros and cons of other approaches</li><li>Maintain conversational style, not a technical report</li></ul><h3 id="stage-3-present-design" tabindex="-1">Stage 3: Present Design <a class="header-anchor" href="#stage-3-present-design" aria-label="Permalink to &quot;Stage 3: Present Design&quot;">​</a></h3><p>Once AI believes it understands your requirements, it presents the design in segments:</p><p><strong>Segmentation rules</strong>:</p><ul><li>200-300 words per segment (avoid information overload)</li><li>Ask &quot;Does this look correct?&quot; after each segment</li><li>Cover: architecture, components, data flow, error handling, testing</li><li>Can backtrack for clarification anytime if something doesn&#39;t make sense</li></ul><h3 id="stage-4-save-document" tabindex="-1">Stage 4: Save Document <a class="header-anchor" href="#stage-4-save-document" aria-label="Permalink to &quot;Stage 4: Save Document&quot;">​</a></h3><p>After design confirmation, AI will:</p><ol><li>Write the design to <code>docs/plans/YYYY-MM-DD-&lt;topic&gt;-design.md</code></li><li>Use clear writing style (if <code>elements-of-style</code> skill is available)</li><li>Commit the design document to git</li></ol><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-present-your-idea" tabindex="-1">Step 1: Present Your Idea <a class="header-anchor" href="#step-1-present-your-idea" aria-label="Permalink to &quot;Step 1: Present Your Idea&quot;">​</a></h3><p><strong>Why</strong> Let AI know what you want to do and trigger the brainstorming workflow.</p><p><strong>Example</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>I want to add user authentication to this project.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>Let me first understand the project status...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(AI checks project files, existing code, documentation)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI continues:</span></span>
<span class="line"><span>Okay, I see this is a web application. Let me ask a few questions to refine the requirements:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>First question: What user authentication method do you expect?</span></span>
<span class="line"><span>A. Email + password login</span></span>
<span class="line"><span>B. Third-party login (Google/GitHub)</span></span>
<span class="line"><span>C. Phone number verification code login</span></span></code></pre></div><p><strong>What you should see</strong>: AI first checks project context, then asks the first question.</p><h3 id="step-2-answer-questions-loop" tabindex="-1">Step 2: Answer Questions (Loop) <a class="header-anchor" href="#step-2-answer-questions-loop" aria-label="Permalink to &quot;Step 2: Answer Questions (Loop)&quot;">​</a></h3><p><strong>Why</strong> Through multiple iterations, let AI precisely understand your requirements.</p><p><strong>Example</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>I choose A, but also want to support B.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>Got it. Primary authentication is email + password, with Google and GitHub third-party login support.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Next question: Do you need to support &quot;remember me&quot; functionality?</span></span>
<span class="line"><span>A. Yes, users can stay logged in for 7 days</span></span>
<span class="line"><span>B. No, users must re-login after closing browser</span></span></code></pre></div><p><strong>What you should see</strong>: AI continues to ask the next refinement question based on your answer.</p><h3 id="step-3-explore-solutions" tabindex="-1">Step 3: Explore Solutions <a class="header-anchor" href="#step-3-explore-solutions" aria-label="Permalink to &quot;Step 3: Explore Solutions&quot;">​</a></h3><p><strong>Why</strong> After AI fully understands requirements, it proposes different implementation approaches for you to choose.</p><p><strong>Example</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI response:</span></span>
<span class="line"><span>Great, I&#39;ve understood your requirements. Let me analyze several implementation approaches:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Approach 1: Self-built authentication system** (recommended)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pros:</span></span>
<span class="line"><span>- Complete control over data and behavior</span></span>
<span class="line"><span>- No external dependencies</span></span>
<span class="line"><span>- Flexible for future expansion</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Cons:</span></span>
<span class="line"><span>- Need to handle password storage, token management, security details</span></span>
<span class="line"><span>- Larger development effort</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Approach 2: Use Auth0-like service**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pros:</span></span>
<span class="line"><span>- Ready out of the box, quick implementation</span></span>
<span class="line"><span>- Automatically handles security details</span></span>
<span class="line"><span>- Supports multiple third-party logins</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Cons:</span></span>
<span class="line"><span>- Paid service (limited free tier)</span></span>
<span class="line"><span>- Data hosted by third party</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I recommend Approach 1, because your project already has its own database architecture,</span></span>
<span class="line"><span>and long-term self-built systems are more flexible. What do you think?</span></span></code></pre></div><p><strong>What you should see</strong>: AI recommends 2-3 approaches, provides trade-off analysis, and expresses a preference.</p><h3 id="step-4-segment-by-segment-design-review" tabindex="-1">Step 4: Segment-by-Segment Design Review <a class="header-anchor" href="#step-4-segment-by-segment-design-review" aria-label="Permalink to &quot;Step 4: Segment-by-Segment Design Review&quot;">​</a></h3><p><strong>Why</strong> Presenting design in segments lets you verify step by step, avoiding information overload.</p><p><strong>Example</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Okay, let&#39;s go with Approach 1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>Okay, I&#39;ll present the detailed design. I&#39;ll break it into several parts.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**Part 1: Architecture Design**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>The authentication system will use JWT (JSON Web Token) architecture. After successful frontend login,</span></span>
<span class="line"><span>the backend returns a JWT containing user information and signature, which the frontend stores in localStorage.</span></span>
<span class="line"><span>Subsequent requests include this token in the Authorization header, and the backend validates the signature</span></span>
<span class="line"><span>to extract user information.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Token is set to expire in 1 hour, refresh token set to 7 days.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Does this part look correct?</span></span></code></pre></div><p><strong>What you should see</strong>: AI presents the first part of the design (architecture) and asks if it&#39;s correct.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>This part looks good.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>**Part 2: Database Design**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Need the following tables:</span></span>
<span class="line"><span>- users: store user basic info (id, email, password_hash, created_at)</span></span>
<span class="line"><span>- refresh_tokens: store refresh tokens (id, user_id, token_hash, expires_at)</span></span>
<span class="line"><span>- social_accounts: store third-party account associations (id, user_id, provider, provider_id)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Passwords encrypted with bcrypt, cost factor 10.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Does this part look correct?</span></span></code></pre></div><p><strong>What you should see</strong>: AI continues to present the next part of the design (database), asking for confirmation after each part.</p><h3 id="step-5-save-design-document" tabindex="-1">Step 5: Save Design Document <a class="header-anchor" href="#step-5-save-design-document" aria-label="Permalink to &quot;Step 5: Save Design Document&quot;">​</a></h3><p><strong>Why</strong> Save the confirmed design as a document for future implementation and review.</p><p><strong>Example</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User input:</span></span>
<span class="line"><span>Looks all good.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI response:</span></span>
<span class="line"><span>Great! I&#39;ll now save the design document.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(AI writes docs/plans/2026-02-01-user-authentication-design.md)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>AI continues:</span></span>
<span class="line"><span>Design document saved: docs/plans/2026-02-01-user-authentication-design.md</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I&#39;ve committed the design document to git.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ready to set up the implementation environment?</span></span></code></pre></div><p><strong>What you should see</strong>:</p><ol><li>Design document saved to <code>docs/plans/</code> directory</li><li>File committed to git</li><li>AI asks if you want to proceed to the next stage (setting up environment)</li></ol><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p><strong>Verify brainstorming workflow is working correctly</strong></p><ul><li>[ ] AI proactively asks questions before coding</li><li>[ ] Asks only one question at a time</li><li>[ ] Provides multiple choice options (when applicable)</li><li>[ ] Proposes 2-3 implementation approaches with trade-offs</li><li>[ ] Presents design in segments, asking for confirmation after each</li><li>[ ] Design document saved to <code>docs/plans/</code> directory</li><li>[ ] Design document committed to git</li></ul><p>If any of the above doesn&#39;t meet expectations, it might be a skill loading issue. Check the <a href="./../../start/installation/">Installation Guide</a> or <a href="./../../faq/troubleshooting/">Troubleshooting</a>.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-pitfall-1-skipping-questions-and-writing-code-directly" tabindex="-1">❌ Pitfall 1: Skipping questions and writing code directly <a class="header-anchor" href="#❌-pitfall-1-skipping-questions-and-writing-code-directly" aria-label="Permalink to &quot;❌ Pitfall 1: Skipping questions and writing code directly&quot;">​</a></h3><p><strong>Symptom</strong>: You just stated a requirement, and AI immediately starts writing code without asking questions.</p><p><strong>Cause</strong>: brainstorming skill not loaded or triggered correctly.</p><p><strong>Solution</strong>:</p><ol><li>Check if skill is installed: verify <code>skills/brainstorming/SKILL.md</code> exists</li><li>Confirm skill path is correct: different platforms have different skill discovery mechanisms</li><li>Manual trigger: use <code>/brainstorm</code> command to force invocation</li></ol><h3 id="❌-pitfall-2-asking-too-many-questions-at-once" tabindex="-1">❌ Pitfall 2: Asking too many questions at once <a class="header-anchor" href="#❌-pitfall-2-asking-too-many-questions-at-once" aria-label="Permalink to &quot;❌ Pitfall 2: Asking too many questions at once&quot;">​</a></h3><p><strong>Symptom</strong>: AI asked 3-5 questions in one message, causing information overload.</p><p><strong>Cause</strong>: AI didn&#39;t follow the &quot;one question at a time&quot; principle.</p><p><strong>Solution</strong>:</p><ul><li>Remind AI: &quot;One question at a time&quot;</li><li>If too many questions, answer the first few and let AI continue</li></ul><h3 id="❌-pitfall-3-design-document-not-saved" tabindex="-1">❌ Pitfall 3: Design document not saved <a class="header-anchor" href="#❌-pitfall-3-design-document-not-saved" aria-label="Permalink to &quot;❌ Pitfall 3: Design document not saved&quot;">​</a></h3><p><strong>Symptom</strong>: After design confirmation, no file generated under <code>docs/plans/</code>.</p><p><strong>Cause</strong>: AI skipped the &quot;save document&quot; step.</p><p><strong>Solution</strong>:</p><ul><li>Explicitly request: &quot;Please save the design document to docs/plans/ directory&quot;</li><li>Check if <code>docs/plans/</code> directory exists; manually create if not</li></ul><h3 id="❌-pitfall-4-design-is-too-complex" tabindex="-1">❌ Pitfall 4: Design is too complex <a class="header-anchor" href="#❌-pitfall-4-design-is-too-complex" aria-label="Permalink to &quot;❌ Pitfall 4: Design is too complex&quot;">​</a></h3><p><strong>Symptom</strong>: Design document includes many &quot;might need in the future&quot; features.</p><p><strong>Cause</strong>: AI didn&#39;t follow the YAGNI principle.</p><p><strong>Solution</strong>:</p><ul><li>Remind AI: &quot;Keep it simple, only implement what&#39;s needed now&quot;</li><li>During brainstorming, explicitly state &quot;not needed for now&quot;</li></ul><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Brainstorming is one of Superpowers&#39; core workflows, ensuring:</p><ol><li><strong>Design before coding</strong>: Don&#39;t skip requirement clarification and solution exploration</li><li><strong>One question at a time</strong>: Avoid information overload, refine requirements step by step</li><li><strong>Explore alternatives</strong>: Propose 2-3 approaches with trade-offs to make informed choices</li><li><strong>Incremental validation</strong>: Present design in small 200-300 word segments for step-by-step confirmation</li><li><strong>Document</strong>: Save confirmed design as a document for future implementation</li></ol><p><strong>Remember</strong>: brainstorming is not a suggestion, but a mandatory workflow. AI will automatically trigger this skill before any creative work begins.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../planning-workflow/">Planning Workflow: Writing Plans</a></strong>.</p><p>After design confirmation, you&#39;ll learn:</p><ul><li>How to break down designs into executable small tasks</li><li>How each task includes complete code and verification steps</li><li>Ensure plans are clear enough that &quot;engineers without context can execute&quot;</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Brainstorming skill definition</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md" target="_blank" rel="noreferrer"><code>skills/brainstorming/SKILL.md</code></a></td><td>1-55</td></tr><tr><td>/brainstorm command definition</td><td><a href="https://github.com/obra/superpowers/blob/main/commands/brainstorm.md" target="_blank" rel="noreferrer"><code>commands/brainstorm.md</code></a></td><td>1-7</td></tr><tr><td>Workflow overview</td><td><a href="https://github.com/obra/superpowers/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>80-96</td></tr></tbody></table><p><strong>Key Principles</strong>:</p><ul><li>One question at a time - Avoid information overload</li><li>Multiple choice preferred - Easier to answer</li><li>YAGNI (You Aren&#39;t Gonna Need It) - Remove unnecessary features</li><li>Explore alternatives - Propose 2-3 approaches</li><li>Incremental validation - Present design in segments</li><li>Be flexible - Can backtrack for clarification anytime</li></ul><p><strong>Key Workflows</strong>:</p><ul><li>Understand idea: Check project context → Ask one question at a time</li><li>Explore solutions: Propose 2-3 approaches with trade-offs → Recommend and explain rationale</li><li>Present design: Present in segments (200-300 words) → Confirm after each segment</li><li>Save document: Write to <code>docs/plans/YYYY-MM-DD-&lt;topic&gt;-design.md</code> → Commit to git</li></ul></details>`,94)])])}const h=n(i,[["render",o]]);export{g as __pageData,h as default};
